declare float @_Z4pownfi(float, i32)

define float @test_pown_afn_ninf_nnan_f32__x_known_positive(float nofpclass(ninf nsub nnorm) %x, i32 %y) {
entry:
  %call = tail call nnan ninf afn float @_Z4pownfi(float %x, i32 %y)
  ret float %call
}

define float @test_finite(i32 %x, i32 %y) {
  %xf = sitofp i32 %x to float
  %yf = sitofp i32 %y to float
  %call = call float @llvm.amdgcn.fmul.legacy(float %xf, float %yf)
  ret float %call
}

define half @test_si_si_i12_mul_C_fail_overflow(i12 noundef %x_in) {
  %x = or i12 %x_in, -64
  %xf = sitofp i12 %x to half
  %r = fmul half %xf, 0xHD400
  ret half %r
}

define half @test_si_si_i16_mul_C_fail_no_promotion(i16 noundef %x_in) {
  %x = or i16 %x_in, -4097
  %xf = sitofp i16 %x to half
  %r = fmul half %xf, 0xH4500
  ret half %r
}

define half @test_si_si_i16_mul_C_fail_overflow(i16 noundef %x_in) {
  %x = or i16 %x_in, -129
  %xf = sitofp i16 %x to half
  %r = fmul half %xf, 0xH5800
  ret half %r
}

define half @test_ui_ui_i8_mul_C_fail_overlow(i8 noundef %x_in) {
  %x = and i8 %x_in, 14
  %xf = uitofp i8 %x to half
  %r = fmul half %xf, 0xH4CC0
  ret half %r
}

define <2 x half> @fmul_sel_op1(i1 %b, <2 x half> %p) {
  %x = fadd <2 x half> %p, <half 0xH3C00, half 0xH4000>
  %s = select i1 %b, <2 x half> zeroinitializer, <2 x half> <half 0xHFFFF, half 0xHFFFF>
  %r = fmul nnan nsz <2 x half> %x, %s
  ret <2 x half> %r
}

define float @fold(float %a) {
  %mul = fmul fast float %a, 0x3FF3333340000000
  %mul1 = fmul fast float %mul, 0x4002666660000000
  ret float %mul1
}

define float @notfold(float %a) {
  %mul = fmul fast float %a, 0x3FF3333340000000
  %mul1 = fmul float %mul, 0x4002666660000000
  ret float %mul1
}

define <3 x float> @mul_mixed_zero_nnan_ninf_vec(<3 x float> nofpclass(nan inf) %a) {
entry:
  %ret = fmul <3 x float> %a, <float -0.000000e+00, float 0.000000e+00, float poison>
  ret <3 x float> %ret
}

@x = external global double
@r1 = external global double
@r2 = external global double

define void @missing_arcp_flag_on_div(double %a) {
entry:
